"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[383],{5878:(D,B,l)=>{l.r(B),l.d(B,{data:()=>e});const e=JSON.parse('{"key":"v-9d35ea78","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D0%BD%D0%BE%D0%B2%D0%B8%D0%BA%D0%BE%D0%B2-%D0%BE%D0%B1-%D0%B0%D0%B4%D0%B5%D0%BA%D0%B2%D0%B0%D1%82%D0%BD%D0%BE%D1%81%D1%82%D0%B8-%D1%81%D1%80%D0%B5%D0%B4%D1%81%D1%82%D0%B2-%D1%86%D0%B5%D0%BB%D0%B8.html","title":"Об адекватности средств цели","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[],"git":{"updatedTime":1730823854000},"filePathRelative":"глушковские-чтения/новиков-об-адекватности-средств-цели.md"}')},4976:(D,B,l)=>{l.r(B),l.d(B,{default:()=>k});var e=l(6252);const t=(0,e._)("h1",{id:"об-адекватности-средств-цели",tabindex:"-1"},[(0,e._)("a",{class:"header-anchor",href:"#об-адекватности-средств-цели","aria-hidden":"true"},"#"),(0,e.Uk)(" Об адекватности средств цели")],-1),a=(0,e._)("p",null,"Новиков Г. Б., г. Киев. Перевод с украинского.",-1),n=(0,e._)("p",null,"Поворот, который произошел в отношении понятия «государство» в официальной советской философской традиции после смерти В. И. Ленина, носит все черты ныне модного перформативного. Акцент сместился,— был вполне сознательно, последовательно и целенаправленно смещен,— с цели: созидания общества действительного гуманизма, на процесс, на средство и на,— по сути,— квазицель — строительство социалистического государства. Орган — государство, приступил к замещению организма — общества.",-1),u=(0,e._)("p",null,"Разумеется, изначально сами внешние условия,— преимущественно, или же и исключительно мобилизационный тип развития страны,— неумолимо диктовали логику укрепления молодого пролетарского государства: «...выполнение общих дел, вытекающих из природы всякого общества» [К. Маркс] во многом требовали тех же практик, что и государство буржуазное. Строгой иерархии, железной дисциплины, предельной централизации, классовой морали, невероятных самоограничений, нередко: жертвенности и самоотречения, необходимой меры насилия, исключительного энтузиазма и подвижничества, мощного аппарата принуждения, власти профессионалов — «государственников» и т.д.",-1),r=(0,e._)("p",null,"Однако же, было и нечто очень специфическое, что дало позднее повод и все основания говорить о социалистическом государстве как несравненно, непостижимо более прогрессивном, по сравнению со своим предшественником: государством буржуазным.",-1),p=(0,e._)("p",null,"Но опыт неумолимо свидетельствует: мало частную собственность на средства производства абсолютного меньшинства персонифицированных субъектов ее объявить, юридически и даже практически сделать частной собственностью одного анонимного, десубъективированного институционализированного собственника — государства. Даже социалистического.",-1),_=(0,e._)("p",null,"Для действительно революционного изменения общественного бытия каждого, многих и всех на деле должно произойти коренное,— качественное,- переустройство всех, без малейшего исключения, сфер жизни общества, первой и самой мощной предпосылкой для чего, безусловно, является такая концентрация. Концентрация колоссального капитала, основной задачей которого больше не является накопление нового мертвого труда, но: создание условий для осуществления,— созидания и воспроизводства,— целостного человека, что и есть, несомненно, то специфическое, и то существенно главное, что отличает государство социалистическое от такого же буржуазного.",-1),d=(0,e._)("p",null,"«Диктатура пролетариата ...не есть только насилие над эксплуататорами и даже не главным образом насилие. Экономической основой этого революционного насилия, залогом его жизненности и успеха является то, что пролетариат представляет и осуществляет высший тип общественной организации труда, по сравнению с капитализмом. В этом суть. В этом источник силы и залог неизбежной полной победы коммунизма» [Ленин В. И., ПСС. т. 39. ст. 13].",-1),i=(0,e._)("p",null,"История Советской России и потому — СССР и есть, по сути, такая попытка осуществления высшего типа общественной организации. История драматическая. Показательна в этом смысле судьба проекта Общегосударственной автоматизированной система сбора и обработки информации (ОГАС), мыслившегося его автором и идеологом академиком В. М. Глушковым, как адекватная задаче система преодоления,— в его терминологии: «второго информационного барьера». Барьер этот, в свою очередь, был обусловлен масштабами современного ему хозяйства,— гражданского и военного,— которое адекватно постичь (а далее, постигнув, адекватно организовать и поступательно развивать) по-старому и с помощью даже «суммарной мощности умов всех участников производства» уже в принципе не представлялось возможным. Как результат — реальная и даже неизбежная перспектива кризиса. Ведь только при условии развития адекватных технологий возможна адекватная же координация и управление в обществе: «ситуация меняется каждый день, а потому и планирование должно быть текучим (планирование в движении) и способным к маневрированию ресурсами для выполнения поставленной задачи обеспечения обороны страны и материального процветания общества» [А. Птицын, «Успехи пещерного социализма в СССР»].",-1),h=(0,e._)("p",null,"Сейчас долгосрочный и затратный проект ОГАС был отклонен руководством СССР, а «спасать» советскую экономику решили с помощью частичного возврата к, по сути, атавистическим капиталистическим формам стимулирования (т. н. косыгинская реформа). Результат известен. Результат поучительный. Учитывая хотя бы то, что отрицательный результат — тоже результат.",-1),s=(0,e._)("p",null,"Несмотря даже на то, что «реальный» социализм, как показала практика, имел очевидную и нарастающую,— по мере отступления, отхода от науки о подлинном гуманизме, а главное — учитывая практическую конкретику, условия, в которых происходило «социалистическое строительство», — тенденцию к затуханию нового способа производства, нового способа жизнебытия — факт движения имел всемирно-историческое значение именно в смысле необратимости развития нового способа производства, качественно нового этапа экономической жизни, нового общественного строя. При этом, как насущная встала проблема своевременного востребования результатов творчества, ведь именно оно является способом бытия общества действительного гуманизма.",-1),c={},k=(0,l(3744).Z)(c,[["render",function(D,B){const l=(0,e.up)("RouterLink");return(0,e.wg)(),(0,e.iD)("div",null,[t,a,(0,e._)("p",null,[(0,e.Uk)("Из материалов конференции "),(0,e.Wm)(l,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,e.w5)((()=>[(0,e.Uk)("«Глушковские чтения»")])),_:1}),(0,e.Uk)(" 2013 года.")]),n,u,r,p,_,d,i,h,s])}]])}}]);